DetectionRule.DetectionLogic:
let SuspiciousCommands = dynamic([ "vssadmin delete shadows", "wmic shadowcopy delete", "bcdedit /set {default} recoveryenabled no", "bcdedit /set {default} bootstatuspolicy ignoreallfailures", "wbadmin delete catalog", "wbadmin delete systemstatebackup" ]);
let SuspiciousPowerShell = @" (Get-WmiObject Win32_ShadowCopy).Delete() | Remove-WmiObject -Query "SELECT * FROM Win32_ShadowCopy" | Remove-WmiObject | Set-ItemProperty -Path "HKLM:\SYSTEM\CurrentControlSet\Services\VSS" "@;
DeviceProcessEvents | where Timestamp > ago(1h) | where // Command line shadow copy deletion (CommandLine has_any (SuspiciousCommands) and not CommandLine contains "@") or // PowerShell shadow copy manipulation (ProcessCommandLine has_any (split(SuspiciousPowerShell, '|')) and ProcessCommandLine !contains "Get-Help") or // WMI shadow copy deletion (ProcessCommandLine contains "Win32_ShadowCopy" and ProcessCommandLine contains "Delete") or // Registry modification disabling shadow copies (ActionType == "RegistryValueSet" and RegistryKey endswith "\VSS" and RegistryValueName in~ ("ShadowCopyStorage", "MinDiffAreaFileSize")) | extend CommandLower = tolower(CommandLine) | where CommandLower !contains "test" and CommandLower !contains "#" and CommandLower !contains "*echo*" | extend ThreatScore = case( CommandLine has "bcdedit" and CommandLine has "recoveryenabled no", 95, CommandLine has "vssadmin delete", 90, CommandLine has "wmic shadowcopy", 88, true, 85 ) | project-reorder Timestamp, DeviceId, FileName, CommandLine, ThreatScore

let SuspiciousParents = dynamic([ "winword.exe", "excel.exe", "powerpnt.exe", "outlook.exe", "acrord32.exe", "rdpclip.exe", "mshta.exe", "regsvr32.exe" ]);
let SuspiciousChildren = dynamic([ "cmd.exe", "powershell.exe", "wscript.exe", "cscript.exe", "msiexec.exe", "rundll32.exe", "certutil.exe", "bitsadmin.exe", "psexec.exe", "wmic.exe", "schtasks.exe", "at.exe" ]);
let RansomwareIndicators = dynamic([ "-enc", "-EncodedCommand", "-ExecutionPolicy", "-nop", "IEX", "Invoke-Expression", "DownloadFile", "DownloadString", "Net.WebClient", "Start-BitsTransfer", "Invoke-WebRequest" ]);
DeviceProcessEvents | where Timestamp > ago(2h) | where InitiatingProcessFileName in~ (SuspiciousParents) or InitiatingProcessFileName in~ (SuspiciousChildren) | where FileName in~ (SuspiciousChildren) or (FileName endswith ".ps1" and ProcessCommandLine has_any (RansomwareIndicators)) or ProcessCommandLine has_any (RansomwareIndicators) | extend ParentChildCombo = strcat(InitiatingProcessFileName, " -> ", FileName) | extend RiskScore = case( InitiatingProcessFileName in~ (SuspiciousParents) and FileName == "powershell.exe", 95, InitiatingProcessFileName in~ (SuspiciousParents) and FileName == "cmd.exe", 90, InitiatingProcessFileName endswith "rundll32.exe" and ProcessCommandLine contains "-s", 98, InitiatingProcessFileName == "mshta.exe", 93, true, 85 ) | where RiskScore >= 85 | summarize EventCount = count(), RiskScore = max(RiskScore), Commands = makeset(ProcessCommandLine) by DeviceId, InitiatingProcessFileName, InitiatingProcessCommandLine, FileName, ProcessCommandLine, ParentChildCombo | where EventCount >= 2 or RiskScore >= 90 | project-reorder Timestamp, DeviceId, ParentChildCombo, RiskScore, EventCount

DetectionRule.Name:
Ransom Note Creation Dete} Ransom Note Creation Detection Detects creation of ransom notes and related files containing payment demands, typically with extensions like .txt, .html, .hta, or named README, RECOVER, RESTORE. Identifies attacker attempts to communicate payment and recovery instructions. Critical Impact T1486 Critical (99%) 99% T1486 - Data Encrypted for Impact Ryuk, Conti, LockBit, BlackCat, Egregor, Ragnar
let RansomNoteNames = dynamic([ "README", "readme", "RECOVER", "recover", "RESTORE", "restore", "RECOVERY", "recovery", "HELP", "help", "INSTRUCTION", "instruction", "HOW_TO_DECRYPT", "decrypt", "unlock", "DECRYPT", "FILES", "!README", "!RECOVER", "!DECRYPT" ]);
let RansomNoteExtensions = dynamic([ ".txt", ".html", ".htm", ".hta", ".bmp", ".jpg", ".png" ]);
let RansomKeywords = dynamic([ "ransom", "payment", "bitcoin", "btc", "cryptocurrency", "decrypt", "encrypted", "restore", "recover", "unlock", "pay", "contact", "tor", "onion", "monero", "xmr", "wallet", "key", "private" ]);
DeviceFileEvents | where Timestamp > ago(1h) | where ActionType in~ ("FileCreated", "FileRenamed") | extend Extension = tolower(tostring(split(FileName, '.')[-1])) | extend BaseName = tostring(split(FileName, '.')[0]) | where // Match known ransom note names (BaseName in~ (RansomNoteNames) and Extension in~ (RansomNoteExtensions)) or // Files with ransom-related keywords in name (FileName has_any (RansomKeywords) and Extension in~ (RansomNoteExtensions)) or // Suspicious file creation patterns (Extension in~ (RansomNoteExtensions) and (FileName has "!" or FileName has "#" or FileName has "_LOCK_") and FileSize < 102400) // Typical note size < 100KB | where not(FileName has "recovery") and not(FileName has "Recovery") | extend NoteScore = case( BaseName in~ (RansomNoteNames), 99, FileName has_any (RansomKeywords), 95, true, 90 ) | project-reorder Timestamp, DeviceId, FileName, FolderPath, NoteScore
1 Critical New true true true
PT1H
ITAdministrator* SecurityTeam*
explorer.exe notepad.exe
IMMEDIATE: Isolate all affected devices Do NOT pay the ransom - contact authorities Preserve ransom notes for law enforcement Identify full scope of encryption Initiate full incident response protocol Engage law enforcement and cyber insurance
Exclude IT team recovery documentation Allow legitimate security awareness testing Time-based exclusions for maintenance Review for penetration test activities
Data Staging Archive Creation Pre-Encryption Detects bulk file staging operations that precede ransomware encryption, including large-scale file copying, archiving, and compression activities targeting sensitive data repositories. This behavior is characteristic of double/triple extortion ransomware operations that exfiltrate data before encryption to increase pressure on victims. Critical Collection, Impact T1560.001, T1486 High (94%) 95% T1560.001 - Archive Collected Data, T1486 - Data Encrypted for Impact BlackCat, LockBit, Conti, Royal, BianLian
let SensitiveFolders = dynamic([ "Financial", "Finance", "HR", "Human Resources", "Payroll", "Legal", "Contracts", "IP", "Trade Secrets", "R&D", "Executive", "Board", "Confidential", "Customer", "Client" ]);
let ArchiveTools = dynamic([ "7z.exe", "7za.exe", "rar.exe", "WinRAR", "Bandizip", "PeaZip", "IZArc", "Hamster", "FreeArc", "ZPAQ", "Compress-Archive", "tar", "gzip", "7z", "WinZip" ]);
let MassCopyIndicators = dynamic([ "xcopy /s", "robocopy", "copy /b", "xcopy", "robocopy.*\\/MIR", "robocopy.*\\/E", "xcopy.*\\/S" ]);
// Detect rapid archive creation in sensitive locations DeviceProcessEvents | where Timestamp > ago(2h) | where InitiatingProcessFileName has_any (ArchiveTools) or ProcessCommandLine has_any (ArchiveTools) | where FolderPath has_any (SensitiveFolders) or ProcessCommandLine has_any (SensitiveFolders) | extend ArchiveOperation = case( ProcessCommandLine has "7z", "7-Zip Archive", ProcessCommandLine has "rar", "RAR Archive", ProcessCommandLine has "Compress-Archive", "PowerShell Compress", ProcessCommandLine has "tar", "TAR Archive", "Generic Archive" ) | summarize ArchiveCount = count(), TotalSizeMB = sum(tolong(ProcessCommandLine)), SensitiveTargets = make_set(FolderPath, 10), ArchivesCreated = make_set(FileName, 10) by bin(Timestamp, 10m), DeviceName, UserName, ArchiveOperation | where ArchiveCount >= 5
union
// Detect mass file copying to staging locations DeviceFileEvents | where Timestamp > ago(2h) | where ActionType in ("FileCreated", "FileRenamed") and FileSize > 10485760 // 10MB files | where FolderPath has_any (SensitiveFolders) or FileName has_any ("classified", "confidential", "secret", "proprietary") | where not(InitiatingProcessFileName in~ ( "explorer.exe", "OneDrive.exe", "Teams.exe", "Outlook.exe", "svchost.exe" )) | summarize FileCount = count(), TotalSize = sum(FileSize), UniqueFiles = dcount(FileName) by bin(Timestamp, 10m), DeviceName, UserName, FolderPath | where FileCount >= 50 | extend StagingIndicator = case( TotalSize > 1073741824, "Large Staging (>1GB)", FileCount > 100, "Mass File Collection", "Suspicious File Activity" )
PT2H PT2H 1 GreaterThan PT30M
Critical Data Staging Detected - Likely Double/Triple Extortion Ransomware Activity Detected bulk data staging and archiving operations on {DeviceName}, consistent with ransomware data exfiltration prior to encryption. This indicates imminent double/triple extortion ransomware attack.
IMMEDIATE: Isolate affected device from network IMMEDIATE: Preserve all staging locations as evidence Identify all data accessed and potential exfiltration Notify cyber insurance and law enforcement immediately Begin incident response for double extortion scenario Prepare for potential data breach notifications
Exclude authorized backup operations during maintenance windows Exclude known data migration projects with proper documentation IT administrative activities during approved change windows
Volume Shadow Copy Enumeration via WMI Detects enumeration and deletion attempts of Volume Shadow Copies using Windows Management Instrumentation (WMI). Ransomware groups use WMI to identify and delete shadow copies to prevent data recovery, often using tools like vssadmin, wmic, or PowerShell WMI calls to execute "shadow copy deletion" commands remotely. Critical Impact T1490 Critical (98%) 97% T1490 - Inhibit System Recovery LockBit, BlackCat, Conti, REvil, DarkSide
let ShadowCopyKeywords = dynamic([ "shadowcopy", "shadow copy", "vssadmin", "win32_shadowcopy", "\\\\.\\root\\cimv2", "Win32_ShadowCopy", "Delete", "Remove" ]);
let DeletionCommands = dynamic([ "delete", "remove", "resize", "revert", "discard" ]);
// Detect WMI-based shadow copy enumeration and deletion DeviceProcessEvents | where Timestamp > ago(1h) | where InitiatingProcessFileName in~ ("wmic.exe", "powershell.exe", "pwsh.exe", "cmd.exe") or ProcessCommandLine has_any (ShadowCopyKeywords) | where ProcessCommandLine has_any (DeletionCommands) or ProcessCommandLine matches regex @"(?i)(shadow.*copy).*(delete|remove|resize)" or ProcessCommandLine matches regex @"Win32_ShadowCopy.*(Delete|Remove)" | extend ShadowCopyActivity = case( ProcessCommandLine has "vssadmin delete", "VSSAdmin Direct Deletion", ProcessCommandLine has "Win32_ShadowCopy", "WMI ShadowCopy Deletion", ProcessCommandLine has "wmic.*shadow", "WMIC Shadow Manipulation", "Shadow Copy Enumeration" ) | summarize EventCount = count(), CommandLines = make_set(ProcessCommandLine, 5), Tools = make_set(InitiatingProcessFileName, 5) by bin(Timestamp, 5m), DeviceName, ShadowCopyActivity, UserName | where EventCount >= 2
union
// Detect PowerShell WMI shadow copy manipulation DeviceEvents | where Timestamp > ago(1h) | where ActionType == "PowershellNSEScript" and AdditionalFields has_any ("Win32_ShadowCopy", "WMI", "Delete") | extend ScriptContent = tostring(AdditionalFields.ScriptContent) | where ScriptContent matches regex @"(?i)(Get-WmiObject|Get-CimInstance).*(Win32_ShadowCopy)" | summarize EventCount = count(), Scripts = make_set(ScriptContent, 3) by bin(Timestamp, 5m), DeviceName, UserName | where EventCount >= 1
PT1H PT1H 1 GreaterThan PT1H
Critical Volume Shadow Copy Enumeration/Deletion Detected - Ransomware Prevention Evasion Detected Volume Shadow Copy enumeration and/or deletion attempts via WMI on {DeviceName}. This is a critical ransomware indicator as attackers disable recovery mechanisms before encryption.
IMMEDIATE: Isolate affected device Check for shadow copy deletion (vssadmin list shadows) Attempt shadow copy recovery if available Verify backup integrity and availability Enable Volume Shadow Copy on all critical systems Implement WMI event filtering for shadow copy operations
Exclude authorized backup software operations Exclude IT administrative shadow copy management Documented system maintenance procedures
